import { useParams } from "react-router-dom";
import { GetFixtures } from "../services/fixture-service";
import { useEffect, useState } from "react";
import { Fixture } from "../objects/fixture";

export default function Fixtures()
{
    const param = useParams();
    const [data, setData] = useState<Fixture | null>(null);
    useEffect(() => {
        GetFixtures(param.id).then(data => setData(data));
    }, []);  
    
    return(
        <div>
            { data ? <>  <div>{data.HomeTeamScore}</div> <div>{data.AwayTeamScore}</div> </>
            
            
            : <p>Loading...</p>}
        </div>
    )

}
